    const MOD = 10**9 + 7;
    points.sort((a, b) => a[0] - b[0] || a[1] - b[1]);
    const yCounts: Record<number, number> = {};
    points.forEach(([x, y]) => {
        yCounts[y] = (yCounts[y] || 0) + 1;
    });

